2079	  /**
2080	   * Calculates landed cost from FOB, agent, duty, freight. Returns null if freight is missing.
2081	   */
2082	  private calculateLandedCost(data: any): string | null {
2083	    const freight = data[this.getMasterFiledName('freight')];
2084	    if (!freight) return null;
2085	    const fob_cost = data[this.getMasterFiledName('fob_cost')];
2086	    if (!fob_cost) return null;
2087	    const agent = data[this.getMasterFiledName('agent')] ?? 0;
2088	    const dutyRateRaw = data[this.getMasterFiledName('duty_rate')];
2089	    const duty_rate = dutyRateRaw?.title ?? dutyRateRaw ?? 0;
2090	    const duty_rate_dollar_amount = data['duty_rate_dollar_amount'] ?? 0;
2091	    const costInclDutyAgent = ((parseFloat(fob_cost) * (1 + (parseFloat(agent) / 100))) * (1 + (parseFloat(duty_rate) / 100)) + parseFloat(duty_rate_dollar_amount)).toFixed(7);
2092	    return (parseFloat(costInclDutyAgent) + parseFloat(freight)).toFixed(7);
2093	  }
