3835	  dateComparator(date1: any, date2: any): number {
3836	    const toTime = (value: any): number => {
3837	      if (!value) return 0;
3838	
3839	      // Already a Date
3840	      if (value instanceof Date) {
3841	        return value.getTime();
3842	      }
3843	
3844	      // Try to parse anything else as a date
3845	      const parsed = new Date(value);
3846	      if (!isNaN(parsed.getTime())) {
3847	        return parsed.getTime();
3848	      }
3849	
3850	      // Fallback: if it's a string like "MM/DD/YYYY", try manual parsing
3851	      if (typeof value === 'string' && value.includes('/')) {
3852	        const [m, d, y] = value.split('/').map(v => parseInt(v, 10));
3853	        const manual = new Date(y, m - 1, d);
3854	        return isNaN(manual.getTime()) ? 0 : manual.getTime();
3855	      }
3856	
3857	      return 0;
3858	    };
3859	
3860	    const t1 = toTime(date1);
3861	    const t2 = toTime(date2);
3862	
3863	    // Standard comparator: negative if t1 < t2, positive if t1 > t2
3864	    return t1 - t2;
3865	  }
